policing-pre-handling-profiles.pre-handling-profile:
${policing\-pre\-handling\-profile\-name}
<#if pbits\-green?has_content>
<#list pbits\-green as gpbit>

    pre-handling-entry-${policing\-pre\-handling\-profile\-name}-pbit${gpbit}


        ${vlan\-tag}
        ${gpbit}


    green              

</#list>
</#if>
<#if pbits\-yellow?has_content>
<#list pbits\-yellow as ypbit>

    pre-handling-entry-${policing\-pre\-handling\-profile\-name}-pbit${ypbit}


        ${vlan\-tag}
        ${ypbit}


    yellow              

</#list>
</#if>   
<#if pbits\-red?has_content>
<#list pbits\-red as rpbit>

    pre-handling-entry-${policing\-pre\-handling\-profile\-name}-pbit${rpbit}


        ${vlan\-tag}
        ${rpbit}


    red              

</#list>
</#if>     
<#if dei0\-color?has_content>

    pre-handling-entry-${policing\-pre\-handling\-profile\-name}-dei0



          ${vlan\-tag}
          0



    ${dei0\-color}              

</#if>      
<#if dei1\-color?has_content>

    pre-handling-entry-${policing\-pre\-handling\-profile\-name}-dei1



          ${vlan\-tag}
          1



    ${dei1\-color}              

</#if>
